const o=t=>{if(!t)return"";if(typeof t=="string"&&t.match(/^\d{4}-\d{2}-\d{2}/)){const[n,a,i]=t.split(" ")[0].split("-");return`${i}/${a}/${n}`}const e={day:"2-digit",month:"2-digit",year:"numeric"};return new Date(t).toLocaleDateString("pt-BR",e)},s=t=>{const e={day:"2-digit",month:"2-digit",year:"numeric",hour:"2-digit",minute:"2-digit",second:"2-digit"};return new Date(t).toLocaleString("pt-BR",e)},c=t=>{if(!t)return"";if(t.includes("T")){const e=new Date(t);return`${e.getFullYear()}${("0"+(e.getMonth()+1)).slice(-2)}${("0"+e.getDate()).slice(-2)}`}if(t.includes("-"))return t.replace(/-/g,"");if(t.includes("/")){const e=t.split(" ")[0].split("/");return`${e[2]}${e[1]}${e[0]}`}return""},d=t=>{const[e,r,n]=t.split("/");return`${r}/${n}`},m=t=>{if(!t)return"";const[e,r,n]=t.split("/");return`${n}-${r.padStart(2,"0")}-${e.padStart(2,"0")}`};export{s as a,d as b,m as c,o as d,c as f};
